import { IconProps } from '@/types/iconProps';
import { FC, ReactNode } from 'react';

export const createIcon = (
  displayName: string,
  path: ReactNode,
): FC<IconProps> => {
  const Icon: FC<IconProps> = ({
    size = 24,
    color = 'currentColor',
    ...props
  }) => (
    <svg
      viewBox="0 0 24 24"
      width={size}
      height={size}
      fill="none"
      stroke={color}
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      {...props}
    >
      {path}
    </svg>
  );

  Icon.displayName = displayName;
  return Icon;
};
